import{_ as i,o as a,c as r,ae as t}from"./chunks/framework.Czhw_PXq.js";const d=JSON.parse('{"title":"股市趋势技术分析圣经 - 第9章：均值测量理论","description":"详解均值测量理论的原理与应用，学会预测股价运动幅度的实用方法","frontmatter":{"title":"股市趋势技术分析圣经 - 第9章：均值测量理论","description":"详解均值测量理论的原理与应用，学会预测股价运动幅度的实用方法","date":"2026-04-18","author":"技术分析研习社","tags":["均值测量","价格目标","技术分析","夏巴克","形态测量"],"category":"技术分析","cover":"/images/sta/chapter9-cover.jpg"},"headers":[],"relativePath":"posts/sta-chapter-9.md","filePath":"posts/sta-chapter-9.md"}'),o={name:"posts/sta-chapter-9.md"};function e(n,l,s,u,h,p){return a(),r("div",null,[...l[0]||(l[0]=[t('<h1 id="第9章-均值测量理论" tabindex="-1">第9章：均值测量理论 <a class="header-anchor" href="#第9章-均值测量理论" aria-label="Permalink to &quot;第9章：均值测量理论&quot;">​</a></h1><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>在股票技术分析中，预测股价运动的幅度与预测方向同样重要。理查德·W·夏巴克在本章中介绍的<strong>均值测量理论（Measuring Formula）</strong>，是技术分析中用于估计股价运动幅度的实用工具。</p><p>虽然夏巴克警告说&quot;我们从来没有找到过一个可靠的时机选择或衡量公式&quot;，但均值测量理论仍然为我们提供了有价值的参考框架，帮助我们判断某个形态是否值得操作，以及比较不同形态的潜在获利空间。</p><h2 id="一、均值测量理论的基本原理" tabindex="-1">一、均值测量理论的基本原理 <a class="header-anchor" href="#一、均值测量理论的基本原理" aria-label="Permalink to &quot;一、均值测量理论的基本原理&quot;">​</a></h2><h3 id="_1-1-为什么需要测量理论" tabindex="-1">1.1 为什么需要测量理论？ <a class="header-anchor" href="#_1-1-为什么需要测量理论" aria-label="Permalink to &quot;1.1 为什么需要测量理论？&quot;">​</a></h3><p>在实际交易中，我们需要回答以下问题：</p><ul><li>这个形态是否值得操作？</li><li>不同图表中的形态哪个能带来更大的潜在利润？</li><li>股价运动的目标价位在哪里？</li></ul><p><strong>测量理论的价值</strong>：</p><ul><li>提供价格目标的估计</li><li>帮助评估风险收益比</li><li>为交易决策提供量化依据</li></ul><h3 id="_1-2-基本原理" tabindex="-1">1.2 基本原理 <a class="header-anchor" href="#_1-2-基本原理" aria-label="Permalink to &quot;1.2 基本原理&quot;">​</a></h3><p>均值测量理论的基本思想是：</p><blockquote><p>&quot;形态的高度可以用来预测后续股价运动的幅度。&quot;</p></blockquote><p><strong>核心逻辑</strong>：</p><ul><li>测量形态的高度（从最高点到最低点的垂直距离）</li><li>从突破点开始，在同样方向量出同样的距离</li><li>得到的点大约对应着第一次阻挡的价格水平</li></ul><h3 id="_1-3-重要提醒" tabindex="-1">1.3 重要提醒 <a class="header-anchor" href="#_1-3-重要提醒" aria-label="Permalink to &quot;1.3 重要提醒&quot;">​</a></h3><p><strong>夏巴克的警告</strong>：</p><ul><li>&quot;我们从来没有找到过一个可靠的时机选择或衡量公式&quot;</li><li>&quot;证券价格具有周期性，但各周期的持续时间各不相同&quot;</li><li>&quot;这种规则只是大概的，而且存在许多例外情况&quot;</li></ul><p><strong>正确态度</strong>：</p><ul><li>测量理论提供的是粗略的估计</li><li>不应作为唯一的交易依据</li><li>需要结合其他技术因素综合判断</li></ul><h2 id="二、头肩形态的测量" tabindex="-1">二、头肩形态的测量 <a class="header-anchor" href="#二、头肩形态的测量" aria-label="Permalink to &quot;二、头肩形态的测量&quot;">​</a></h2><h3 id="_2-1-头肩顶的测量方法" tabindex="-1">2.1 头肩顶的测量方法 <a class="header-anchor" href="#_2-1-头肩顶的测量方法" aria-label="Permalink to &quot;2.1 头肩顶的测量方法&quot;">​</a></h3><p><strong>测量步骤</strong>：</p><ol><li>量出头部顶端至颈线底部的垂直距离</li><li>从突破颈线点开始，向下量出同样的垂直距离</li><li>得到的点大约对应着第一次支撑的价格水平</li></ol><p><strong>示例</strong>：</p><ul><li>头部顶端：100</li><li>颈线底部：90</li><li>形态高度：10个点</li><li>突破点：88</li><li>测量目标：88 - 10 = 78</li></ul><h3 id="_2-2-头肩底的测量方法" tabindex="-1">2.2 头肩底的测量方法 <a class="header-anchor" href="#_2-2-头肩底的测量方法" aria-label="Permalink to &quot;2.2 头肩底的测量方法&quot;">​</a></h3><p><strong>测量步骤</strong>：</p><ol><li>量出头部底端至颈线顶部的垂直距离</li><li>从突破颈线点开始，向上量出同样的垂直距离</li><li>得到的点大约对应着第一次阻力的价格水平</li></ol><h3 id="_2-3-实际应用注意事项" tabindex="-1">2.3 实际应用注意事项 <a class="header-anchor" href="#_2-3-实际应用注意事项" aria-label="Permalink to &quot;2.3 实际应用注意事项&quot;">​</a></h3><p><strong>注意事项一：第一次阻挡</strong></p><ul><li>这种阻挡可能很短暂</li><li>也可能持续一段时间</li><li>之后新建立的趋势将继续进行</li></ul><p><strong>注意事项二：例外情况</strong></p><ul><li>这种方法有许多例外情况</li><li>只是一种粗略的估计</li></ul><p><strong>注意事项三：最重要的结论</strong></p><ul><li>对于头肩形态最重要也最可信的结论是：</li><li>股票价格运动趋势将出现反转</li><li>新的趋势将持续足够长的时间，供我们进行获利操作</li></ul><h2 id="三、三角形形态的测量" tabindex="-1">三、三角形形态的测量 <a class="header-anchor" href="#三、三角形形态的测量" aria-label="Permalink to &quot;三、三角形形态的测量&quot;">​</a></h2><h3 id="_3-1-对称三角形的测量" tabindex="-1">3.1 对称三角形的测量 <a class="header-anchor" href="#_3-1-对称三角形的测量" aria-label="Permalink to &quot;3.1 对称三角形的测量&quot;">​</a></h3><p><strong>测量方法</strong>：</p><ul><li>测量形态开始处（底边）的价格幅度</li><li>从突破点开始，在突破方向量出同样的距离</li></ul><p><strong>特点</strong>：</p><ul><li>由于对称三角形的预测方向不明确</li><li>需要等待突破后才能进行测量</li></ul><h3 id="_3-2-直角三角形的测量" tabindex="-1">3.2 直角三角形的测量 <a class="header-anchor" href="#_3-2-直角三角形的测量" aria-label="Permalink to &quot;3.2 直角三角形的测量&quot;">​</a></h3><p><strong>上升三角形</strong>：</p><ul><li>测量形态的高度（水平顶边到最低点的距离）</li><li>从突破点向上量出同样的距离</li></ul><p><strong>下降三角形</strong>：</p><ul><li>测量形态的高度（水平底边到最高点的距离）</li><li>从突破点向下量出同样的距离</li></ul><h3 id="_3-3-楔形形态的测量" tabindex="-1">3.3 楔形形态的测量 <a class="header-anchor" href="#_3-3-楔形形态的测量" aria-label="Permalink to &quot;3.3 楔形形态的测量&quot;">​</a></h3><p><strong>测量方法</strong>：</p><ul><li>测量楔形的最大宽度</li><li>从突破点开始，在突破方向量出同样的距离</li></ul><p><strong>特点</strong>：</p><ul><li>楔形形态突破后的运动往往比较迅速</li><li>测量目标通常较快达到</li></ul><h2 id="四、旗形与三角旗形的测量" tabindex="-1">四、旗形与三角旗形的测量 <a class="header-anchor" href="#四、旗形与三角旗形的测量" aria-label="Permalink to &quot;四、旗形与三角旗形的测量&quot;">​</a></h2><h3 id="_4-1-旗形的测量" tabindex="-1">4.1 旗形的测量 <a class="header-anchor" href="#_4-1-旗形的测量" aria-label="Permalink to &quot;4.1 旗形的测量&quot;">​</a></h3><p><strong>测量方法</strong>：</p><ul><li>测量&quot;旗杆&quot;的高度（从形态开始到旗形形成前的快速运动幅度）</li><li>从旗形突破点开始，在突破方向量出同样的距离</li></ul><p><strong>特点</strong>：</p><ul><li>旗形测量是技术分析中比较可靠的测量方法之一</li><li>后续运动往往能达到测量目标</li></ul><h3 id="_4-2-三角旗形的测量" tabindex="-1">4.2 三角旗形的测量 <a class="header-anchor" href="#_4-2-三角旗形的测量" aria-label="Permalink to &quot;4.2 三角旗形的测量&quot;">​</a></h3><p><strong>测量方法</strong>：</p><ul><li>与旗形相同</li><li>测量旗杆的高度</li><li>从突破点开始量出同样距离</li></ul><h3 id="_4-3-实际案例" tabindex="-1">4.3 实际案例 <a class="header-anchor" href="#_4-3-实际案例" aria-label="Permalink to &quot;4.3 实际案例&quot;">​</a></h3><p><strong>案例：迪尔公司（Deere &amp; Co.）1936年</strong></p><p><strong>旗杆</strong>：</p><ul><li>1月22日突破对称三角形态</li><li>三周时间内上涨17点至75</li></ul><p><strong>旗面</strong>：</p><ul><li>股价在两条间隔3½点的平行线间波动</li></ul><p><strong>突破</strong>：</p><ul><li>3月5日明确突破</li></ul><p><strong>测量</strong>：</p><ul><li>旗杆高度：约17点</li><li>突破点：约74</li><li>测量目标：74 + 17 = 91</li></ul><p><strong>实际走势</strong>：</p><ul><li>不到五周时间，股价一路飙升至89</li><li>基本达到测量目标</li></ul><h2 id="五、矩形形态的测量" tabindex="-1">五、矩形形态的测量 <a class="header-anchor" href="#五、矩形形态的测量" aria-label="Permalink to &quot;五、矩形形态的测量&quot;">​</a></h2><h3 id="_5-1-测量方法" tabindex="-1">5.1 测量方法 <a class="header-anchor" href="#_5-1-测量方法" aria-label="Permalink to &quot;5.1 测量方法&quot;">​</a></h3><p><strong>步骤</strong>：</p><ol><li>测量矩形的高度（上边界与下边界之间的距离）</li><li>从突破点开始，在突破方向量出同样的距离</li></ol><h3 id="_5-2-实际案例" tabindex="-1">5.2 实际案例 <a class="header-anchor" href="#_5-2-实际案例" aria-label="Permalink to &quot;5.2 实际案例&quot;">​</a></h3><p><strong>案例：泛美公司（Transamerica）1935年</strong></p><p><strong>矩形形态</strong>：</p><ul><li>股价在7½-8之间波动</li><li>矩形高度：约0.5点</li></ul><p><strong>突破</strong>：</p><ul><li>10月21日突破向上</li><li>突破点：约8</li></ul><p><strong>测量目标</strong>：</p><ul><li>8 + 0.5 = 8.5</li></ul><p><strong>实际走势</strong>：</p><ul><li>五周后，股价涨幅超过60%</li><li>远超测量目标</li></ul><p><strong>说明</strong>：</p><ul><li>矩形形态的测量往往比较保守</li><li>实际涨幅可能远超测量目标</li></ul><h2 id="六、双重顶与双重底的测量" tabindex="-1">六、双重顶与双重底的测量 <a class="header-anchor" href="#六、双重顶与双重底的测量" aria-label="Permalink to &quot;六、双重顶与双重底的测量&quot;">​</a></h2><h3 id="_6-1-双重顶的测量" tabindex="-1">6.1 双重顶的测量 <a class="header-anchor" href="#_6-1-双重顶的测量" aria-label="Permalink to &quot;6.1 双重顶的测量&quot;">​</a></h3><p><strong>测量方法</strong>：</p><ul><li>测量从顶部到谷底的距离（两顶之间的跌幅）</li><li>从突破谷底支撑点开始，向下量出同样的距离</li></ul><p><strong>特点</strong>：</p><ul><li>双重顶的测量相对可靠</li><li>后续下跌往往能达到或超过测量目标</li></ul><h3 id="_6-2-双重底的测量" tabindex="-1">6.2 双重底的测量 <a class="header-anchor" href="#_6-2-双重底的测量" aria-label="Permalink to &quot;6.2 双重底的测量&quot;">​</a></h3><p><strong>测量方法</strong>：</p><ul><li>测量从底部到峰顶的距离（两底之间的涨幅）</li><li>从突破峰顶阻力点开始，向上量出同样的距离</li></ul><h2 id="七、测量理论的应用原则" tabindex="-1">七、测量理论的应用原则 <a class="header-anchor" href="#七、测量理论的应用原则" aria-label="Permalink to &quot;七、测量理论的应用原则&quot;">​</a></h2><h3 id="_7-1-基本原则" tabindex="-1">7.1 基本原则 <a class="header-anchor" href="#_7-1-基本原则" aria-label="Permalink to &quot;7.1 基本原则&quot;">​</a></h3><p><strong>原则一：测量理论提供的是估计值</strong></p><ul><li>不是精确的预测</li><li>只是大概的价格目标</li></ul><p><strong>原则二：第一次阻挡</strong></p><ul><li>测量目标通常对应第一次阻挡</li><li>阻挡可能很短暂，也可能持续一段时间</li></ul><p><strong>原则三：新趋势继续</strong></p><ul><li>突破阻挡后，新趋势将继续</li><li>股价可能运动更远</li></ul><h3 id="_7-2-实战应用建议" tabindex="-1">7.2 实战应用建议 <a class="header-anchor" href="#_7-2-实战应用建议" aria-label="Permalink to &quot;7.2 实战应用建议&quot;">​</a></h3><p><strong>建议一：用于比较不同形态</strong></p><ul><li>比较不同股票的潜在获利空间</li><li>选择测量目标更大的形态进行操作</li></ul><p><strong>建议二：设置获利目标</strong></p><ul><li>在测量目标附近考虑部分获利了结</li><li>不要期望每次都达到精确目标</li></ul><p><strong>建议三：结合其他因素</strong></p><ul><li>测量理论应结合支撑阻力位使用</li><li>考虑趋势线和形态的特征</li><li>结合成交量变化确认</li></ul><h3 id="_7-3-常见错误" tabindex="-1">7.3 常见错误 <a class="header-anchor" href="#_7-3-常见错误" aria-label="Permalink to &quot;7.3 常见错误&quot;">​</a></h3><p><strong>错误一：过度依赖测量结果</strong></p><ul><li>将测量目标作为精确预测</li><li>忽视其他技术信号</li></ul><p><strong>错误二：忽视例外情况</strong></p><ul><li>认为测量总是准确的</li><li>没有准备应对测量失败的情况</li></ul><p><strong>错误三：不考虑市场环境</strong></p><ul><li>在弱势市场中期望达到测量目标</li><li>忽视整体市场趋势的影响</li></ul><h2 id="八、测量理论与支撑阻力的结合" tabindex="-1">八、测量理论与支撑阻力的结合 <a class="header-anchor" href="#八、测量理论与支撑阻力的结合" aria-label="Permalink to &quot;八、测量理论与支撑阻力的结合&quot;">​</a></h2><h3 id="_8-1-相互验证" tabindex="-1">8.1 相互验证 <a class="header-anchor" href="#_8-1-相互验证" aria-label="Permalink to &quot;8.1 相互验证&quot;">​</a></h3><p><strong>理想情况</strong>：</p><ul><li>测量目标恰好位于历史支撑或阻力位</li><li>这种重合增加了目标的可信度</li></ul><p><strong>实际应用</strong>：</p><ul><li>如果测量目标与支撑阻力位重合 → 目标更可靠</li><li>如果测量目标位于空白区域 → 需要更谨慎</li></ul><h3 id="_8-2-动态调整" tabindex="-1">8.2 动态调整 <a class="header-anchor" href="#_8-2-动态调整" aria-label="Permalink to &quot;8.2 动态调整&quot;">​</a></h3><p><strong>情况一：快速达到目标</strong></p><ul><li>如果股价快速达到测量目标</li><li>考虑部分获利了结</li><li>观察是否能突破继续</li></ul><p><strong>情况二：未达到目标即反转</strong></p><ul><li>如果股价在达到目标前反转</li><li>可能是测量错误或其他技术信号更强</li><li>应及时调整策略</li></ul><p><strong>情况三：突破目标继续运动</strong></p><ul><li>如果股价突破测量目标继续运动</li><li>说明趋势非常强劲</li><li>可以持有或加仓</li></ul><h2 id="九、本章总结" tabindex="-1">九、本章总结 <a class="header-anchor" href="#九、本章总结" aria-label="Permalink to &quot;九、本章总结&quot;">​</a></h2><p>本章我们学习了均值测量理论：</p><ol><li><p><strong>基本原理</strong>：</p><ul><li>形态高度可以用来预测后续运动幅度</li><li>从突破点量出同样距离得到目标价位</li><li>提供的是粗略估计，不是精确预测</li></ul></li><li><p><strong>各类形态的测量</strong>：</p><ul><li>头肩形态：头部到颈线的距离</li><li>三角形：形态的高度</li><li>旗形/三角旗形：旗杆的高度</li><li>矩形：上下边界的距离</li><li>双重顶/底：顶底之间的幅度</li></ul></li><li><p><strong>应用原则</strong>：</p><ul><li>用于比较不同形态的潜在获利空间</li><li>设置获利目标的参考</li><li>结合支撑阻力位使用</li></ul></li><li><p><strong>注意事项</strong>：</p><ul><li>存在许多例外情况</li><li>不是百分之百可靠</li><li>需要结合其他技术因素综合判断</li></ul></li></ol><p><strong>核心原则</strong>：</p><ul><li>测量理论是辅助工具，不是主要依据</li><li>提供的是价格目标的估计范围</li><li>成功的交易需要综合多种分析方法</li></ul><hr><p><strong>延伸阅读</strong>：</p><ul><li>第7章：趋势线与通道</li><li>第8章：支撑与阻力</li><li>第10章：虚假移动与陷阱</li></ul><p><strong>免责声明</strong>：本文仅供学习交流使用，不构成投资建议。股市有风险，投资需谨慎。</p>',142)])])}const c=i(o,[["render",e]]);export{d as __pageData,c as default};
